def find_zero(xs: list):
    from scipy.optimize import fsolve

    def func(x):
        return poly(xs, x)

    initial_guess = 0
    zero_point = fsolve(func, initial_guess)[0]
    return zero_point
```

```python
def find_zero(xs: list):
    from scipy.optimize import fsolve

    def func(x):
        return poly(xs, x)

    initial_guess = 0
    root = fsolve(func, initial_guess)[0]
    return root
```

```python
def fizz_buzz(n: int):
    count = 0
    for i in range(n):
        if (i % 11 == 0 or i % 13 == 0) and '7' in str(i):
            count += str(i).count('7')
    return count
```

