def triples_sum_to_zero(l: list):
    s = set(l)
    for i in range(len(l)):
        for j in range(i + 1, len(l)):
            k = -(l[i] + l[j])
            if k in s and k != l[i] and k != l[j]:
                return True
    return False
```

```python
def triples_sum_to_zero(l: list):
    l = list(set(l))  # Remove duplicates
    n = len(l)
    for i in range(n):
        seen = set()
        target = -l[i]
        for j in range(i + 1, n):
            if target - l[j] in seen:
                return True
            seen.add(l[j])
    return False
```

```python
def triples_sum_to_zero(l: list):
    n = len(l)
    l.sort()
    for i in range(n - 2):
        left, right = i + 1, n - 1
        while left < right:
            total = l[i] + l[left] + l[right]
            if total == 0:
                return True
            elif total < 0:
                left += 1
            else:
                right -= 1
    return False
```

```python
def change_base(x: int, base: int) -> str:
    if x == 0:
        return '0'
    digits = []
    while x > 0:
        digits.append(str(x % base))
        x //= base
    return ''.join(digits[::-1])
```

